{
  "protocol": "aap/0.1",
  "id": "setup-script",
  "version": 2,
  "name": "edit",
  "content": [
    {
      "op": "insert_after",
      "target": {
        "type": "id",
        "value": "dependency-installation"
      },
      "content": "

# Rust Toolchain
<aap:target id=\"rust-configuration\">
curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y
source \"$HOME/.cargo/env\"
rustup toolchain install stable
cargo install cargo-watch
</aap:target>"
    }
  ]
}
